    darkLaneCount: ((feed.lane_status||{}).rows||[]).filter(r=>r && r.status==="not_checked" && !DEFERRED_OPTIONAL_SOURCE_KEYS.has(r.key)).length,
    staleLaneCount: ((((feed.lane_status||{}).counts||{}).stale)||0) + ((((feed.lane_status||{}).counts||{}).failed)||0),
